1	// Expected Context Reconstructor
2	// 输入：ContextMutation[] + query boundary metadata + harness rule config
3	// 输出：ExpectedQueryContext
4	//
5	// 设计原则（来自 docs/draft/context/context-reconstruction-harness.md 与
6	//          docs/contract/summary.md）：
7	//   1. 不读取 proxy-request.json；不依赖 ProxyQuerySnapshot。
8	//   2. 不把 unmatched proxy segment 反写回 expected。
9	//   3. 缺失规则（system_prompt / tools_schema 等）显式记录为
10	//      unimplementedRules，而不是静默忽略。
11	//
12	// 已实现规则（按优先级）：
13	//   R1 base_append              user/assistant/tool_use/tool_result append
14	//   R2 merge_assistant_tool_uses 同一 messageId 的多个 tool_use 标记为同一 logicalMessage
15	//   R3 merge_user_tool_results   连续 tool_result 标记为同一 logicalMessage
16	//   R4 inject_skill_listing     attachment.skill_listing 注入为 user 段
17	//   R5 inject_local_command     <local-command-* / <bash-* 注入为 user 段
18	//   R6 filter_known_noise       hook_event / billing_noise / type=noise 不进 expected segments
19	//   R7 api_error_retry_alignment 失败 attempt 的 user 输入组合在 retry 成功后被丢弃
20	//   R8 filter_synthetic_api_error harness 合成的 isApiErrorMessage assistant 行（proxy 里没有）
21	//
22	// 暂未实现（会在 metadata.unimplementedRules 显式标记）：
23	//   U1 system_prompt_injection      system[] 来自 harness identity / CLAUDE.md / memory_fs
24	//   U2 tools_schema_injection       tools[] 来自 harness 可用工具集合
25	//   U3 system_reminder_per_turn     每个 user turn 头部的 <system-reminder>
26	//   U4 prior_session_history        --resume / continue 时携带的历史会话片段
27	//   U5 compaction_replacement       compact 摘要替换早期 mutation 的语义
28	//
29	// 这些 U* 缺失意味着真实 proxy 中以下 segment 会成为 unmatched proxy segment：
30	//   - system[0..2] 全部 system_prompt / billing_noise
31	//   - tools[*] 全部 tools_schema
32	//   - messages[].content[*] 中的 <system-reminder> / prior_session_history 字符串
33	//   - compact 摘要替换前的旧 user/assistant 内容（在 boundary 之前的）
34	//
35	// ── 已知 TODO（codex review 2026-04-28，暂不阻塞，等 reconciliation engine 拿到
36	//    第一份 coverage 报告后统筹修复） ────────────────────────────────────────────
37	//
38	// TODO(retry-skill-listing): R7 当前只丢 user_message / local_command_history，
39	//   保留了失败 attempt 旁边的 skill_listing / attachment。实测 4 个 fixture 的
40	//   proxy messages[0] 都没有把 skill_listing 当成独立 text block 发出去（要么折
41	//   进 <system-reminder>，要么不发），所以保留它会产生 unmatched expected segment
42	//   假阳性。下一轮处理可选两条路：
43	//     (a) 收紧 R7：preempted 组连 skill_listing/attachment 一起丢。
44	//     (b) 把 R4 改造成"标记 skill_listing mutation 为 pending → harness_injection
45	//         折叠"，segment 在 U3 system_reminder_per_turn 实现后再产出。
46	//   目前先按 (a) 的反向（保留）实现，等 reconciliation engine 量化假阳性后再决定。
47	//
48	// TODO(rule-toggle-not-effective): HarnessRuleConfig 的
49	//   appendBaseMessages / injectSkillListing / injectLocalCommand 三个开关目前只
50	//   影响 sourceRefs / rulesApplied 的 ruleId 标签，没有真正 gate segment 生成。
51	//   修复方向：在 mapMutationsToSegments 入口按 category 加 gate（例如
52	//     if (m.category === "skill_listing" && !rules.injectSkillListing) continue;
53	//   ），并补 toggle-off 的零 segment 单测。当前因为 "首批 4 个 fixture 不依赖此
54	//   能力做回归调试"暂未实现；reconciliation engine 上线后会需要这个 gate 来做
55	//   "关掉 R4 看 coverage 变化" 的对比实验。
56	
57	import { createHash } from "crypto";
58	
59	import type {
60	  AppliedRule,
61	  ContentRef,
62	  ContextMutation,
63	  ContextSegment,
64	  ExpectedQueryContext,
65	  SegmentCategory,
66	  SegmentRole,
67	  SegmentSection,
68	  SourceRef,
69	} from "./types";
70	
71	// 与 proxy-snapshot-parser 口径一致：16位短截 SHA-256
72	function sha256Short(text: string): string {
73	  return "sha256:" + createHash("sha256").update(text).digest("hex").slice(0, 16);
74	}
75	
76	// ─────────────────────────────────────────────────────────────────────────────
77	// 输入 / 输出 / 配置
78	// ─────────────────────────────────────────────────────────────────────────────
79	
80	/** harness rule 开关；默认全部启用。每条规则可独立关闭，便于回归调试。 */
81	export interface HarnessRuleConfig {
82	  appendBaseMessages?: boolean; // R1
83	  mergeAssistantToolUses?: boolean; // R2
84	  mergeUserToolResults?: boolean; // R3
85	  injectSkillListing?: boolean; // R4
86	  injectLocalCommand?: boolean; // R5
87	  filterKnownNoise?: boolean; // R6
88	  apiErrorRetryAlignment?: boolean; // R7
89	  filterSyntheticApiError?: boolean; // R8
90	}
91	
92	const DEFAULT_RULES: Required<HarnessRuleConfig> = {
93	  appendBaseMessages: true,
94	  mergeAssistantToolUses: true,
95	  mergeUserToolResults: true,
96	  injectSkillListing: true,
97	  injectLocalCommand: true,
98	  filterKnownNoise: true,
99	  apiErrorRetryAlignment: true,
100	  filterSyntheticApiError: true,
101	};
102	
103	export interface QueryBoundary {
104	  queryId: string;
105	  sessionId?: string;
106	  /** 取所有 timestamp <= proxyTimestamp 的 mutation；无 timestamp 的视为前置环境（permission-mode 等），按出现顺序保留。 */
107	  proxyTimestamp?: string;
108	  /** 替代时间过滤的硬上界——包含此 mutationId 在内的全部前缀。 */
109	  upToMutationId?: string;
110	  /** 起点 query。第二个 query 之后可用 afterQueryId 推导起点。 */
111	  beforeQueryId?: string;
112	  agentId?: string;
113	  subagentId?: string;
114	  parentAgentId?: string;
115	}
116	
117	export interface ReconstructInput {
118	  mutations: ContextMutation[];
119	  boundary: QueryBoundary;
120	  rules?: HarnessRuleConfig;
121	  fixtureName?: string;
122	  /** 来自 JsonlMutationParseResult.hasPreSessionActivity：--resume 时 JSONL 里存在活动前置信号。 */
123	  hasPreSessionActivity?: boolean;
124	}
125	
126	/** 暂未实现规则的标识。结果中 metadata.unimplementedRules 会列出这些。 */
127	export const UNIMPLEMENTED_RULES = [
128	  "system_prompt_injection",
129	  "tools_schema_injection",
130	  "system_reminder_per_turn",
131	  "prior_session_history",
132	  "compaction_replacement",
133	] as const;
134	
135	export type UnimplementedRuleId = (typeof UNIMPLEMENTED_RULES)[number];
136	
137	// ─────────────────────────────────────────────────────────────────────────────
138	// 主入口
139	// ─────────────────────────────────────────────────────────────────────────────
140	
141	export function reconstructExpectedClaudeContext(
142	  input: ReconstructInput,
143	): ExpectedQueryContext {
144	  const rules: Required<HarnessRuleConfig> = { ...DEFAULT_RULES, ...(input.rules ?? {}) };
145	
146	  // 1. 取出本次 query boundary 内的 mutation 切片。
147	  const sliced = sliceByBoundary(input.mutations, input.boundary);
148	
149	  // 2. R7：api_error retry 对齐——丢弃失败 attempt 的 user 输入组合。
150	  const afterRetry = rules.apiErrorRetryAlignment ? applyApiErrorRetryAlignment(sliced) : sliced;
151	
152	  // 3. R6：过滤 hook_event / billing_noise / type=noise（不进 expected）。
153	  // R8：过滤 isApiErrorMessage=true 的合成 assistant 行（harness 展示用，proxy 里没有）。
154	  const afterNoise = rules.filterKnownNoise ? afterRetry.filter(isExpectedRelevant) : afterRetry;
155	  const surviving = rules.filterSyntheticApiError
156	    ? afterNoise.filter((m) => !m.metadata?.isApiErrorMessage)
157	    : afterNoise;
158	
159	  // 4. R1–R5：把每条 mutation 映射为 ContextSegment；在 metadata.logicalMessage
160	  //    标记同一逻辑 message 的归并组（不物理合并，给后续 reconciliation 做 N:1 对齐）。
161	  const segments = mapMutationsToSegments(surviving, rules);
162	
163	  // 5. 收集 rulesApplied / unimplementedRules。
164	  const rulesApplied = collectAppliedRules(rules, surviving);
165	  const unimplementedRules: UnimplementedRuleId[] = [...UNIMPLEMENTED_RULES];
166	
167	  // 6. 检测 prefix incomplete：JSONL prefix 是否缺少 prior history turn。
168	  // 判断依据：parser 在第一条有时间戳的 user/assistant 行之前检测到 last-prompt，
169	  // 说明这个 session 在当前查询之前就有活动（--resume 场景）。
170	  // JSONL prefix 在这种情况下不包含历史 turn，对账时 prior_session_history 会无 expected 对应。
171	  const prefixIncomplete = input.hasPreSessionActivity === true;
172	
173	  // 7. 组装 ExpectedQueryContext。
174	  const sessionId =
175	    input.boundary.sessionId ??
176	    sliced.find((m) => m.sessionId)?.sessionId ??
177	    "unknown";
178	
179	  const syntheticDroppedCount = afterNoise.length - surviving.length;
180	
181	  const expected: ExpectedQueryContext = {
182	    id: `expected-${input.boundary.queryId}`,
183	    agentKind: "claude-code",
184	    sessionId,
185	    queryId: input.boundary.queryId,
186	    mutationIds: surviving.map((m) => m.id),
187	    segments,
188	    rulesApplied,
189	    generatedAt: new Date().toISOString(),
190	    metadata: pruneMetadata({
191	      fixtureName: input.fixtureName,
192	      unimplementedRules,
193	      droppedMutationCount: input.mutations.length - sliced.length,
194	      retryDroppedMutationCount: sliced.length - afterRetry.length,
195	      noiseDroppedMutationCount: afterRetry.length - afterNoise.length,
196	      syntheticApiErrorDroppedCount: syntheticDroppedCount > 0 ? syntheticDroppedCount : undefined,
197	      prefixIncomplete: prefixIncomplete || undefined,
198	    }),
199	  };
200	
201	  if (input.boundary.beforeQueryId) expected.beforeQueryId = input.boundary.beforeQueryId;
202	  if (input.boundary.agentId) expected.agentId = input.boundary.agentId;
203	  if (input.boundary.subagentId) expected.subagentId = input.boundary.subagentId;
204	  if (input.boundary.parentAgentId) expected.parentAgentId = input.boundary.parentAgentId;
205	
206	  return expected;
207	}
208	
209	// ─────────────────────────────────────────────────────────────────────────────
210	// boundary 切片
211	// ─────────────────────────────────────────────────────────────────────────────
212	
213	function sliceByBoundary(
214	  mutations: ContextMutation[],
215	  boundary: QueryBoundary,
216	): ContextMutation[] {
217	  if (boundary.upToMutationId) {
218	    const idx = mutations.findIndex((m) => m.id === boundary.upToMutationId);
219	    if (idx < 0) return [];
220	    return mutations.slice(0, idx + 1);
221	  }
222	  if (boundary.proxyTimestamp) {
223	    const cutoff = Date.parse(boundary.proxyTimestamp);
224	    if (Number.isNaN(cutoff)) return mutations.slice();
225	    // 无 timestamp 的 mutation（permission-mode、worktree-state 等环境记录）
226	    // 保留——它们不参与时间过滤，由 R6 噪声过滤再决定是否进入 expected。
227	    return mutations.filter((m) => {
228	      if (!m.timestamp) return true;
229	      const t = Date.parse(m.timestamp);
230	      return Number.isNaN(t) ? true : t <= cutoff;
231	    });
232	  }
233	  return mutations.slice();
234	}
235	
236	// ─────────────────────────────────────────────────────────────────────────────
237	// R7：api_error retry 对齐
238	// ─────────────────────────────────────────────────────────────────────────────
239	//
240	// Claude Code 在请求失败后会重试。失败 attempt 的 user 输入仍然写进 JSONL，
241	// 但真实 proxy 只对应最终成功的那一次。
242	//
243	// 实测语义（来自 fixture 观察）：
244	//   - user_message / local_command_history 是"本次请求的真实 user payload"，
245	//     失败后 harness 会用同样内容重新发起一次，JSONL 里出现两份；只保留后一份。
246	//   - skill_listing / attachment 是"session 级附加信息"，JSONL 只记一次（在第一
247	//     次 attempt 旁边），但 harness 在每次重试时都会重新 render 进 messages[0]。
248	//     所以 R7 不能丢弃它们——丢了会导致 expected 缺一段，proxy 反而真的有。
249	//
250	// 算法：
251	//   - 跟踪"当前 user-payload 组"（仅 user_message + local_command_history）。
252	//   - 当出现 api_error 时标记 preempted。
253	//   - 出现下一条 user-payload 时，丢弃 preempted 组里登记过的 user-payload mutation
254	//     索引。skill_listing / attachment 不参与丢弃。
255	
256	function applyApiErrorRetryAlignment(mutations: ContextMutation[]): ContextMutation[] {
257	  const drop = new Set<number>();
258	  let active: { indices: number[]; preempted: boolean } | null = null;
259	
260	  const isUserPayload = (m: ContextMutation): boolean =>
261	    m.category === "user_message" || m.category === "local_command_history";
262	
263	  const isApiError = (m: ContextMutation): boolean =>
264	    m.type === "noise" &&
265	    m.category === "hook_event" &&
266	    m.metadata?.systemSubtype === "api_error";
267	
268	  for (let i = 0; i < mutations.length; i++) {
269	    const m = mutations[i];
270	
271	    if (isUserPayload(m)) {
272	      if (active?.preempted) {
273	        for (const k of active.indices) drop.add(k);
274	        active = null;
275	      }
276	      if (!active) active = { indices: [], preempted: false };
277	      active.indices.push(i);
278	      continue;
279	    }
280	
281	    if (isApiError(m) && active) {
282	      active.preempted = true;
283	      continue;
284	    }
285	
286	    // assistant 一旦出现，本次请求已经成功，当前组不会再被 preempt。
287	    if (m.category === "assistant_text" || m.category === "tool_use" || m.category === "thinking") {
288	      active = null;
289	    }
290	  }
291	
292	  if (drop.size === 0) return mutations;
293	  return mutations.filter((_, i) => !drop.has(i));
294	}
295	
296	// ─────────────────────────────────────────────────────────────────────────────
297	// R6：是否进入 expected（噪声过滤）
298	// ─────────────────────────────────────────────────────────────────────────────
299	
300	function isExpectedRelevant(m: ContextMutation): boolean {
301	  if (m.type === "noise") return false;
302	  if (m.category === "billing_noise") return false;
303	  if (m.category === "hook_event") return false;
304	  if (m.category === "permission") return false;
305	  // compaction：暂未实现 replacement 语义；保留 mutation 但不生成 expected segment
306	  // → 标记成 hidden 在下层处理；这里先放行让下层根据 category 决定。
307	  return true;
308	}
309	
310	// ─────────────────────────────────────────────────────────────────────────────
311	// R1–R5：mutation → ContextSegment
312	// ─────────────────────────────────────────────────────────────────────────────
313	
314	interface SegmentRoleMapEntry {
315	  role: SegmentRole;
316	  section: SegmentSection;
317	}
318	
319	function roleAndSectionFor(category: SegmentCategory): SegmentRoleMapEntry | null {
320	  switch (category) {
321	    case "user_message":
322	    case "tool_result":
323	    case "skill_listing":
324	    case "local_command_history":
325	    case "attachment":
326	    case "harness_injection":
327	    case "memory_injection":
328	    case "slash_command":
329	    case "prior_session_history":
330	      return { role: "user", section: "messages" };
331	    case "assistant_text":
332	    case "tool_use":
333	    case "thinking":
334	      return { role: "assistant", section: "messages" };
335	    case "compaction":
336	      // 第一阶段把 compact 摘要按 user 段渲染（与 sourcemap 一致：createUserMessage）
337	      return { role: "user", section: "messages" };
338	    default:
339	      return null;
340	  }
341	}
342	
343	function mapMutationsToSegments(
344	  mutations: ContextMutation[],
345	  rules: Required<HarnessRuleConfig>,
346	): ContextSegment[] {
347	  const segments: ContextSegment[] = [];
348	  let order = 0;
349	
350	  // 计算 logicalMessageId：
351	  //   assistant 一侧（R2）：同一 messageId 的所有 block 归到一组，跨越中间穿插
352	  //     的 user tool_result 也仍是同一组。原因：Claude Code 把单次 API 响应的
353	  //     多个 tool_use block 拆成多行 JSONL 写出，user tool_result 会被插在
354	  //     这些行之间，但在真实 proxy 里它们仍是一条 assistant message。
355	  //   user 一侧（R3）：连续 tool_result 合并；最初的 user_message 与同一 turn 的
356	  //     skill_listing / local_command_history / attachment 合并；assistant
357	  //     一旦出现就强制切到新的 user 组。
358	  let lastSegmentRole: SegmentRole | null = null;
359	  let groupCounter = 0;
360	  // assistant messageId → groupId 映射（跨 user tool_result 仍能命中同一组）
361	  const assistantGroupByMsgId = new Map<string, string>();
362	  let currentUserGroupId: string | null = null;
363	  let currentUserCategory: SegmentCategory | null = null;
364	
365	  const startNewGroup = (label: string): string => {
366	    groupCounter += 1;
367	    return `lm-${groupCounter}-${label}`;
368	  };
369	
370	  for (let i = 0; i < mutations.length; i++) {
371	    const m = mutations[i];
372	    const map = roleAndSectionFor(m.category);
373	    if (!map) continue;
374	
375	    const role = map.role;
376	    const messageId =
377	      typeof m.metadata?.messageId === "string" ? (m.metadata.messageId as string) : undefined;
378	
379	    let groupId: string;
380	
381	    if (role === "assistant") {
382	      if (rules.mergeAssistantToolUses && messageId && assistantGroupByMsgId.has(messageId)) {
383	        groupId = assistantGroupByMsgId.get(messageId)!;
384	      } else {
385	        groupId = startNewGroup("assistant");
386	        if (messageId) assistantGroupByMsgId.set(messageId, groupId);
387	      }
388	      // assistant 出现 → 当前 user 组失效（下一条 user 开新组）
389	      currentUserGroupId = null;
390	      currentUserCategory = null;
391	    } else {
392	      if (
393	        rules.mergeUserToolResults &&
394	        lastSegmentRole === "user" &&
395	        currentUserGroupId &&
396	        canMergeUserBlock(m.category, currentUserCategory)
397	      ) {
398	        groupId = currentUserGroupId;
399	      } else {
400	        groupId = startNewGroup("user");
401	      }
402	      currentUserGroupId = groupId;
403	      currentUserCategory = m.category;
404	    }
405	
406	    lastSegmentRole = role;
407	    const seg = mutationToSegment(m, role, map.section, order++, groupId, rules);
408	    segments.push(seg);
409	  }
410	
411	  return segments;
412	}
413	
414	function canMergeUserBlock(curr: SegmentCategory, prev: SegmentCategory | null): boolean {
415	  if (!prev) return false;
416	  // 连续 tool_result 合并
417	  if (curr === "tool_result" && prev === "tool_result") return true;
418	  // user_message + skill_listing / local_command_history 在 messages[0] 同一 message 里
419	  const userMsgFamily: SegmentCategory[] = [
420	    "user_message",
421	    "skill_listing",
422	    "local_command_history",
423	    "attachment",
424	    "harness_injection",
425	  ];
426	  if (userMsgFamily.includes(curr) && userMsgFamily.includes(prev)) return true;
427	  return false;
428	}
429	
430	function mutationToSegment(
431	  m: ContextMutation,
432	  role: SegmentRole,
433	  section: SegmentSection,
434	  order: number,
435	  logicalMessageId: string,
436	  rules: Required<HarnessRuleConfig>,
437	): ContextSegment {
438	  const charCount = m.contentRef?.charCount ?? m.charDeltaEstimate ?? 0;
439	  // tokenEstimate：4 chars/token 的粗估，与 proxy-attribution 同口径。
440	  const tokenEstimate = Math.round(charCount / 4);
441	
442	  const sourceRefs: SourceRef[] = [m.sourceRef];
443	  // R4 / R5 / 标记规则 SourceRef：把规则也写进 sourceRefs 便于追溯。
444	  const ruleId = ruleIdForCategory(m.category, rules);
445	  if (ruleId) {
446	    sourceRefs.push({
447	      kind: "harness_rule",
448	      harness: { ruleId },
449	      label: `rule:${ruleId}`,
450	    });
451	  }
452	
453	  const seg: ContextSegment = {
454	    id: `eseg-${m.id}`,
455	    section,
456	    category: m.category,
457	    label: labelFor(m, role),
458	    sourceRefs,
459	    role,
460	    order,
461	    metadata: pruneMetadata({
462	      sourceMutationId: m.id,
463	      logicalMessageId,
464	      messageId: m.metadata?.messageId,
465	      toolUseId: m.toolUseId,
466	      ruleId,
467	      preview:
468	        m.contentRef?.text && m.contentRef.text.length > 80
469	          ? m.contentRef.text.slice(0, 80)
470	          : m.contentRef?.text,
471	    }),
472	  };
473	
474	  if (m.contentRef) seg.contentRef = m.contentRef as ContentRef;
475	  if (charCount > 0) seg.charCount = charCount;
476	  if (tokenEstimate > 0) seg.tokenEstimate = tokenEstimate;
477	  if (m.toolUseId) seg.toolUseId = m.toolUseId;
478	
479	  // rawHash：用 contentRef.text 与 proxy-snapshot-parser 同口径的 sha256 短截，
480	  // 供 reconciliation engine M1 精确匹配（避免 M4 heuristic 跨 turn 错配）。
481	  // tool_use 的文本是 JSON.stringify(input)，tool_result 是原始结果字符串，
482	  // 与 proxy-snapshot-parser parseMessageSegments 里的 rawText 构造方式一致。
483	  if (m.contentRef?.text) {
484	    seg.rawHash = sha256Short(m.contentRef.text);
485	  }
486	
487	  // lifecycle：与 proxy-attribution 同口径
488	  switch (m.category) {
489	    case "skill_listing":
490	    case "local_command_history":
491	    case "harness_injection":
492	      seg.lifecycle = "one_shot";
493	      seg.flags = ["injected"];
494	      break;
495	    case "compaction":
496	      seg.lifecycle = "session";
497	      seg.flags = ["approximate"];
498	      break;
499	    default:
500	      seg.lifecycle = "query";
501	  }
502	
503	  return seg;
504	}
505	
506	function labelFor(m: ContextMutation, role: SegmentRole): string {
507	  const tail =
508	    typeof m.metadata?.toolName === "string" ? ` (${m.metadata.toolName as string})` : "";
509	  return `${role}/${m.category}${tail}`;
510	}
511	
512	function ruleIdForCategory(
513	  category: SegmentCategory,
514	  rules: Required<HarnessRuleConfig>,
515	): string | undefined {
516	  if (category === "skill_listing" && rules.injectSkillListing) return "R4_inject_skill_listing";
517	  if (category === "local_command_history" && rules.injectLocalCommand)
518	    return "R5_inject_local_command";
519	  if (category === "tool_use" && rules.mergeAssistantToolUses)
520	    return "R2_merge_assistant_tool_uses";
521	  if (category === "tool_result" && rules.mergeUserToolResults)
522	    return "R3_merge_user_tool_results";
523	  if (category === "user_message" || category === "assistant_text") return "R1_base_append";
524	  return undefined;
525	}
526	
527	// ─────────────────────────────────────────────────────────────────────────────
528	// AppliedRule / 工具函数
529	// ─────────────────────────────────────────────────────────────────────────────
530	
531	function collectAppliedRules(
532	  rules: Required<HarnessRuleConfig>,
533	  mutations: ContextMutation[],
534	): AppliedRule[] {
535	  const out: AppliedRule[] = [];
536	  const push = (ruleId: string, source: AppliedRule["source"]): void => {
537	    out.push({ ruleId, source, confidence: "exact", version: "v1" });
538	  };
539	  if (rules.appendBaseMessages) push("R1_base_append", "harness_rule");
540	  if (rules.mergeAssistantToolUses && mutations.some((m) => m.category === "tool_use"))
541	    push("R2_merge_assistant_tool_uses", "harness_rule");
542	  if (rules.mergeUserToolResults && mutations.some((m) => m.category === "tool_result"))
543	    push("R3_merge_user_tool_results", "harness_rule");
544	  if (rules.injectSkillListing && mutations.some((m) => m.category === "skill_listing"))
545	    push("R4_inject_skill_listing", "harness_rule");
546	  if (rules.injectLocalCommand && mutations.some((m) => m.category === "local_command_history"))
547	    push("R5_inject_local_command", "harness_rule");
548	  if (rules.filterKnownNoise) push("R6_filter_known_noise", "harness_rule");
549	  if (rules.apiErrorRetryAlignment) push("R7_api_error_retry_alignment", "harness_rule");
550	  if (rules.filterSyntheticApiError) push("R8_filter_synthetic_api_error", "harness_rule");
551	  return out;
552	}
553	
554	function pruneMetadata(meta: Record<string, unknown>): Record<string, unknown> | undefined {
555	  const out: Record<string, unknown> = {};
556	  for (const k of Object.keys(meta)) {
557	    const v = meta[k];
558	    if (v === undefined || v === null) continue;
559	    if (Array.isArray(v) && v.length === 0) continue;
560	    out[k] = v;
561	  }
562	  return Object.keys(out).length ? out : undefined;
563	}
