1	// proxy-first attribution：消费 snapshot.segments（由 proxy-snapshot-parser 产出），
2	// 对每个 segment 匹配 rule，产出 ProxySegmentAttribution[]。
3	//
4	// 职责边界：
5	//   - 不读取 rawBody，不重建 segment，不 mutate snapshot
6	//   - 不读取 JSONL，不生成 ContextMutation
7	//   - attribution 的 proxySegmentIds 直接使用 parser 产出的 segment.id
8	//   - 所有语义判断均由 CONTEXT_LEDGER_RULES 驱动，attribution 函数本身不写 pattern 假设
9	//
10	// 设计原则（rule 驱动）：
11	//   - 每个 segment 遍历 RULE_TABLE（有序），第一个命中的 rule 决定 attribution 全部字段
12	//   - attribution 函数只处理 rule 无法覆盖的 wire-schema 感知事项：
13	//       · tool_use / tool_result：category 由 parser 的 wire schema 解析直接确定，无文本 pattern
14	//       · billing header fallback：regex 未命中但前缀存在时保守兜底
15	//       · prior_session_guess：messages[0] 结构性推断，无文本 pattern 可写
16	//   - 未命中任何 rule 时明确标 rule_gap，不再用 heuristic 伪装归类
17	//
18	// 规则表（RULE_TABLE）按优先级排列，section 约束由 rule.attribution.location.section 决定：
19	//   优先级 1  side_query rules      (queryScope=side_query)
20	//   优先级 2  billing_noise_pattern (system + messages)
21	//   优先级 3  system prompt rules   (identity / dynamic sections / static body)
22	//   优先级 4  context_management    (system，动态 git 状态)
23	//   优先级 5  tool schema rules     (tools section，每个 tool 独立 rule)
24	//   优先级 6  兜底：wire schema + prior_session_guess + rule_gap
25	
26	import {
27	  CONTEXT_LEDGER_RULES,
28	  CLAUDE_CODE_BILLING_NOISE_RULE,
29	  CLAUDE_CODE_SESSION_GUIDANCE_EMBEDDED_RULE,
30	  CLAUDE_CODE_ENVIRONMENT_SECTION_RULE,
31	  CLAUDE_CODE_AUTO_MEMORY_SECTION_RULE,
32	  CLAUDE_CODE_CONTEXT_MANAGEMENT_RULE,
33	} from "./rule-registry";
34	import type { ContextLedgerRule } from "./rule-registry";
35	import { DYNAMIC_SECTION_HEADERS } from "./proxy-block-splitter";
36	import type {
37	  ContextSegment,
38	  MutationSourceKind,
39	  ProxyQuerySnapshot,
40	  ProxySegmentAttribution,
41	  SegmentCategory,
42	  SegmentFlag,
43	  SegmentLifecycle,
44	  SegmentSection,
45	} from "./types";
46	
47	// ── 常量 ──────────────────────────────────────────────────────────────────────
48	
49	const LARGE_SEGMENT_THRESHOLD = 10_000;
50	
51	// billing header 前缀（fallback 用，regex rule 未命中时的保守兜底）
52	const BILLING_HEADER_PREFIX = "x-anthropic-billing-header:";
53	
54	// messages 里的 harness injection 标签（无文本 pattern rule 可覆盖，保留为 wire schema 检测）
55	const SYSTEM_REMINDER_TAG = "<system-reminder>";
56	const LOCAL_COMMAND_TAGS = [
57	  "<local-command-caveat>",
58	  "<bash-input>",
59	  "<bash-stdout>",
60	  "<bash-stderr>",
61	  "<command-name>",
62	  "<local-command-stdout>",
63	];
64	
65	// ── rule 驱动的 pattern match ──────────────────────────────────────────────────
66	
67	// tryMatchRule：对单条 rule 做匹配，返回命名捕获组（regex）或 true（非 regex 命中）或 null（不命中）。
68	// section 约束和 queryScope 约束在此统一处理，attribution 主流程只调用这一个函数。
69	function tryMatchRule(
70	  rule: ContextLedgerRule,
71	  text: string,
72	  section: SegmentSection,
73	  queryKind: string,
74	): Record<string, string | undefined> | true | null {
75	  const attr = rule.attribution;
76	  if (!attr?.pattern) return null;
77	
78	  // section 约束
79	  if (attr.location?.section !== undefined && attr.location.section !== section) return null;
80	
81	  // queryScope 约束
82	  if (rule.queryScope && rule.queryScope !== "any") {
83	    if (queryKind !== rule.queryScope) return null;
84	  }
85	
86	  if (attr.matchMode === "regex") {
87	    const m = new RegExp(attr.pattern, "s").exec(text);
88	    if (!m) return null;
89	    return (m.groups ?? {}) as Record<string, string | undefined>;
90	  }
91	  if (attr.matchMode === "exact") {
92	    return text === attr.pattern ? true : null;
93	  }
94	  if (attr.matchMode === "contains") {
95	    return text.includes(attr.pattern) ? true : null;
96	  }
97	  // prefix / structural
98	  return text.trimStart().startsWith(attr.pattern) ? true : null;
99	}
100	
101	// findMatchingRule：按 CONTEXT_LEDGER_RULES 顺序遍历，返回第一个命中的 rule + 捕获组。
102	function findMatchingRule(
103	  text: string,
104	  section: SegmentSection,
105	  queryKind: string,
106	): { rule: ContextLedgerRule; groups: Record<string, string | undefined> | null } | null {
107	  for (const rule of CONTEXT_LEDGER_RULES) {
108	    const result = tryMatchRule(rule, text, section, queryKind);
109	    if (result !== null) {
110	      return { rule, groups: result === true ? null : result };
111	    }
112	  }
113	  return null;
114	}
115	
116	// ── rule → attribution 字段映射 ───────────────────────────────────────────────
117	// 从 rule 的 attribution 字段推导出 ProxySegmentAttribution 的各语义字段。
118	// 这里是唯一的"rule → 字段"映射点，attribution 主流程不再重复这些逻辑。
119	
120	interface RuleMatchResult {
121	  category: SegmentCategory;
122	  mechanism: ProxySegmentAttribution["mechanism"];
123	  confidence: ProxySegmentAttribution["confidence"];
124	  attributedSource: MutationSourceKind;
125	  lifecycle: SegmentLifecycle | undefined;
126	  ruleId: string;
127	  flags: SegmentFlag[];
128	  notes: string[] | undefined;
129	}
130	
131	function applyRuleMatch(
132	  rule: ContextLedgerRule,
133	  groups: Record<string, string | undefined> | null,
134	): RuleMatchResult {
135	  const attr = rule.attribution!;
136	
137	  // lifecycle：从 rule.reconstruction.emits.lifecycle 推导
138	  const lifecycle = rule.reconstruction?.emits?.lifecycle;
139	
140	  // flags
141	  const flags: SegmentFlag[] = [];
142	  if (rule.reconstruction?.emits?.flags?.includes("injected")) flags.push("injected");
143	  if (rule.reconstruction?.emits?.flags?.includes("known_noise")) flags.push("known_noise");
144	
145	  // category：从 rule.attribution.category
146	  const category = attr.category;
147	
148	  // mechanism：从 rule.attribution.mechanism
149	  const mechanism = attr.mechanism;
150	
151	  // confidence：有命名捕获组且全部非空 → exact；否则按 rule.reconciliation.confidence 降级
152	  const hasGroups = groups && Object.keys(groups).length > 0;
153	  const allGroupsFilled = hasGroups && Object.values(groups!).every((v) => v !== undefined && v !== "");
154	  const baseConfidence = rule.reconciliation?.confidence ?? "inferred";
155	  const confidence: ProxySegmentAttribution["confidence"] =
156	    attr.matchMode === "exact" ? "exact"
157	    : allGroupsFilled ? "exact"
158	    : hasGroups ? "inferred"
159	    : baseConfidence;
160	
161	  // attributedSource：tool_use/tool_result 由 wire schema 决定，其余由 rule 决定
162	  const attributedSource: MutationSourceKind =
163	    category === "tool_use" || category === "tool_result" ? "jsonl" : "harness_rule";
164	
165	  // notes：billing rule 专用捕获组、dynamic section 专用捕获组
166	  let notes: string[] | undefined;
167	  if (category === "billing_noise" && groups) {
168	    notes = [
169	      `cc_version=${groups["version"] ?? "?"}`,
170	      `cc_entrypoint=${groups["entrypoint"] ?? "?"}`,
171	      ...(groups["cch"] ? [`cch=${groups["cch"]}`] : []),
172	      ...(groups["workload"] ? [`cc_workload=${groups["workload"]}`] : []),
173	    ].filter((n) => !n.endsWith("?"));
174	    if (notes.length === 0) notes = undefined;
175	  } else if (rule.ruleId === CLAUDE_CODE_ENVIRONMENT_SECTION_RULE.ruleId && groups) {
176	    notes = [
177	      `cwd=${groups["cwd"] ?? "?"}`,
178	      `platform=${groups["platform"] ?? "?"}`,
179	      `shell=${groups["shell"] ?? "?"}`,
180	      `osVersion=${groups["osVersion"] ?? "?"}`,
181	      `model=${groups["modelDesc"] ?? "?"}`,
182	      ...(groups["cutoff"] ? [`cutoff=${groups["cutoff"]}`] : []),
183	    ];
184	  } else if (rule.ruleId === CLAUDE_CODE_AUTO_MEMORY_SECTION_RULE.ruleId && groups?.["memoryDir"]) {
185	    notes = [`memoryDir=${groups["memoryDir"]}`];
186	  } else if (rule.ruleId === CLAUDE_CODE_CONTEXT_MANAGEMENT_RULE.ruleId && groups) {
187	    if (groups["currentBranch"]) {
188	      notes = [
189	        `currentBranch=${groups["currentBranch"]}`,
190	        `mainBranch=${groups["mainBranch"] ?? "?"}`,
191	        ...(groups["gitUser"] ? [`gitUser=${groups["gitUser"]}`] : []),
192	      ];
193	    } else {
194	      notes = ["no_git_repo: gitStatus block absent"];
195	    }
196	  }
197	
198	  // Session-specific guidance：embedded variant 升 confidence
199	  if (rule.ruleId === CLAUDE_CODE_SESSION_GUIDANCE_EMBEDDED_RULE.ruleId) {
200	    return { category, mechanism, confidence: "exact", attributedSource, lifecycle, ruleId: rule.ruleId, flags, notes };
201	  }
202	
203	  return { category, mechanism, confidence, attributedSource, lifecycle, ruleId: rule.ruleId, flags, notes };
204	}
205	
206	// ── text 検出工具（wire schema 感知、不依赖文本 pattern rule）────────────────────
207	
208	function isBillingNoise(text: string): boolean {
209	  return text.trimStart().toLowerCase().startsWith(BILLING_HEADER_PREFIX);
210	}
211	
212	function isSystemReminder(text: string): boolean {
213	  return text.trimStart().startsWith(SYSTEM_REMINDER_TAG);
214	}
215	
216	function isLocalCommand(text: string): boolean {
217	  const t = text.trimStart();
218	  return LOCAL_COMMAND_TAGS.some((tag) => t.startsWith(tag));
219	}
220	
221	// ── jsonPath 解析 ─────────────────────────────────────────────────────────────
222	
223	function parseMsgIndex(jsonPath: string | undefined): number | null {
224	  if (!jsonPath) return null;
225	  const m = /reqBody\.messages\[(\d+)\]/.exec(jsonPath);
226	  return m ? parseInt(m[1]!, 10) : null;
227	}
228	
229	// ── 核心函数 ──────────────────────────────────────────────────────────────────
230	
231	/**
232	 * 消费 snapshot.segments，对每个 segment 应用 CONTEXT_LEDGER_RULES，产出 ProxySegmentAttribution[]。
233	 *
234	 * 主流程：每个 segment → findMatchingRule → applyRuleMatch → push attribution。
235	 * Rule 未覆盖的情况（wire schema / prior_session / rule_gap）在主流程末尾兜底。
236	 * attribution 函数本身不写任何 pattern 假设，只处理 rule 无法覆盖的 wire-schema 感知事项。
237	 */
238	export function inferClaudeProxyAttributions(
239	  snapshot: ProxyQuerySnapshot,
240	): ProxySegmentAttribution[] {
241	  const snapshotId = snapshot.id;
242	  const results: ProxySegmentAttribution[] = [];
243	  const queryKind = snapshot.request?.queryKind ?? "unknown";
244	
245	  // 预收集 tool_use id，用于 tool_result cross-reference（wire schema，无文本 pattern）
246	  const knownToolUseIds = new Set<string>();
247	  for (const seg of snapshot.segments) {
248	    if (seg.category === "tool_use" && seg.toolUseId) {
249	      knownToolUseIds.add(seg.toolUseId);
250	    }
251	  }
252	
253	  // 总消息索引数（prior_session_guess 依赖，结构性推断）
254	  const msgIndices = new Set<number>();
255	  for (const seg of snapshot.segments) {
256	    if (seg.section !== "messages") continue;
257	    const ref = seg.sourceRefs[0];
258	    const idx = ref?.kind === "proxy" ? parseMsgIndex(ref.proxy.jsonPath) : null;
259	    if (idx !== null) msgIndices.add(idx);
260	  }
261	  const totalMessages = msgIndices.size;
262	
263	  let attrCounter = 0;
264	
265	  for (const seg of snapshot.segments) {
266	    const segId = seg.id;
267	    const ref = seg.sourceRefs[0];
268	    const jsonPath = ref?.kind === "proxy" ? (ref.proxy.jsonPath ?? "") : "";
269	    const chars = seg.charCount ?? 0;
270	    const rawText = seg.rawText ?? "";
271	    const meta = seg.metadata as Record<string, unknown> | undefined;
272	    const sectionHeader = typeof meta?.["sectionHeader"] === "string" ? meta["sectionHeader"] : null;
273	
274	    let category: SegmentCategory = seg.category;
275	    let mechanism: ProxySegmentAttribution["mechanism"] = "unknown";
276	    let confidence: ProxySegmentAttribution["confidence"] = "inferred";
277	    let attributedSource: MutationSourceKind = "unknown";
278	    let lifecycle: SegmentLifecycle | undefined;
279	    let ruleId: string | undefined;
280	    let notes: string[] | undefined;
281	    const flags: SegmentFlag[] = [];
282	
283	    // ── 主路径：rule 驱动 ────────────────────────────────────────────────────
284	    // findMatchingRule 按 CONTEXT_LEDGER_RULES 顺序遍历，返回第一个命中的 rule。
285	    // section 约束、queryScope 约束、matchMode 全部在 tryMatchRule 里统一处理。
286	
287	    const ruleMatch = findMatchingRule(rawText, seg.section, queryKind);
288	
289	    if (ruleMatch) {
290	      const applied = applyRuleMatch(ruleMatch.rule, ruleMatch.groups);
291	      category = applied.category;
292	      mechanism = applied.mechanism;
293	      confidence = applied.confidence;
294	      attributedSource = applied.attributedSource;
295	      lifecycle = applied.lifecycle;
296	      ruleId = applied.ruleId;
297	      notes = applied.notes;
298	      flags.push(...applied.flags);
299	
300	    // ── 兜底路径：wire schema 感知（无文本 pattern rule 可覆盖）─────────────
301	    } else if (seg.section === "system") {
302	      // billing fallback：regex rule 未命中但前缀存在，说明 billing header 格式异常
303	      if (isBillingNoise(rawText)) {
304	        category = "billing_noise";
305	        mechanism = "billing_noise_pattern";
306	        confidence = "inferred";
307	        attributedSource = "harness_rule";
308	        lifecycle = "noise";
309	        ruleId = CLAUDE_CODE_BILLING_NOISE_RULE.ruleId;
310	        flags.push("known_noise");
311	        notes = ["billing header detected by prefix fallback; regex did not match — format may differ from expected"];
312	      } else {
313	        // rule_gap：system segment 未命中任何 rule
314	        category = "unknown";
315	        mechanism = "unknown";
316	        confidence = "unknown";
317	        attributedSource = "unknown";
318	        lifecycle = "unknown";
319	        flags.push("unexplained");
320	        if (!rawText.trim()) {
321	          notes = ["rule_gap: empty system block"];
322	        } else if (sectionHeader) {
323	          notes = [`rule_gap: section header "${sectionHeader}" has no matching rule — needs rule coverage`];
324	        } else {
325	          notes = ["rule_gap: system block matched no rule — needs rule coverage"];
326	        }
327	      }
328	
329	    } else if (seg.section === "tools") {
330	      // tools segment：rule 未命中（新 tool 尚无 rule，或 tool 来自 MCP/plugin）。
331	      // category/section 由 parser wire schema 确定（exact），只是具体 tool 无对应 rule。
332	      category = "tools_schema";
333	      mechanism = "tools_schema_pattern";
334	      confidence = "exact"; // wire schema 确定，parser 已验证 blk.type
335	      attributedSource = "harness_rule";
336	      lifecycle = "session";
337	      // 从 jsonPath 提取 tool name 做 rule_gap 提示（有助于发现新 tool 需要补 rule）
338	      const toolNameMatch = /reqBody\.tools\[\d+\]/.exec(jsonPath);
339	      notes = [`rule_gap: no matching tool rule for ${toolNameMatch?.[0] ?? "unknown tool"} — add to registry if stable`];
340	
341	    } else if (seg.section === "messages") {
342	      const msgIndex = parseMsgIndex(jsonPath);
343	
344	      if (seg.category === "tool_use") {
345	        // wire schema：category 由 parser 直接确定，无文本 pattern 可写
346	        mechanism = "tool_use_id_match";
347	        confidence = "exact";
348	        attributedSource = "jsonl";
349	        lifecycle = "query";
350	      } else if (seg.category === "tool_result") {
351	        // wire schema + cross-reference tool_use_id
352	        const tid = seg.toolUseId;
353	        const idMatched = !!tid && knownToolUseIds.has(tid);
354	        mechanism = idMatched ? "tool_use_id_match" : "unknown";
355	        confidence = idMatched ? "exact" : "inferred";
356	        attributedSource = "jsonl";
357	        lifecycle = "query";
358	        if (!idMatched) {
359	          notes = [`tool_use_id "${tid ?? "(missing)"}" not found in this request's tool_use blocks — confidence downgraded to inferred`];
360	        }
361	        if (chars > LARGE_SEGMENT_THRESHOLD) {
362	          flags.push("large_segment");
363	          notes = [...(notes ?? []), `large_segment_detector: tool_result ${chars} chars > ${LARGE_SEGMENT_THRESHOLD} threshold`];
364	        }
365	      } else if (isSystemReminder(rawText)) {
366	        // <system-reminder>：harness 注入，无独立文本 pattern rule（内容每次不同）
367	        category = "harness_injection";
368	        mechanism = "system_reminder_pattern";
369	        confidence = "exact";
370	        attributedSource = "harness_rule";
371	        lifecycle = "one_shot";
372	        flags.push("injected");
373	      } else if (isLocalCommand(rawText)) {
374	        // <bash-stdout> 等 local command 标签
375	        category = "local_command_history";
376	        mechanism = "local_command_pattern";
377	        confidence = "exact";
378	        attributedSource = "harness_rule";
379	        lifecycle = "one_shot";
380	        flags.push("injected");
381	      } else if (seg.category === "user_message" && msgIndex === 0 && totalMessages > 1) {
382	        // prior_session_guess：messages[0] 结构性推断，无文本 pattern
383	        category = "prior_session_history";
384	        mechanism = "unknown";
385	        confidence = "inferred";
386	        attributedSource = "prior_session";
387	        lifecycle = "session";
388	        notes = [`prior_session_guess: messages[0] user_message in a ${totalMessages}-message context`];
389	      } else if (seg.category === "user_message" || seg.category === "assistant_text") {
390	        // wire schema 确定类型，attribution 只补充 mechanism
391	        mechanism = "unknown";
392	        confidence = "inferred";
393	        attributedSource = "jsonl";
394	        lifecycle = "query";
395	      } else {
396	        category = "unknown";
397	        mechanism = "unknown";
398	        confidence = "unknown";
399	        attributedSource = "unknown";
400	        lifecycle = "unknown";
401	        flags.push("unexplained");
402	        notes = [`unknown: segment ${segId} category=${seg.category} — no attribution rule matched`];
403	      }
404	
405	    } else {
406	      // 未知 section
407	      mechanism = "unknown";
408	      confidence = "unknown";
409	      attributedSource = "unknown";
410	      notes = [`unknown section: ${seg.section}`];
411	    }
412	
413	    if (chars > LARGE_SEGMENT_THRESHOLD) flags.push("large_segment");
414	
415	    results.push({
416	      id: `attr-${++attrCounter}-${segId.slice(-8)}`,
417	      snapshotId,
418	      proxySegmentIds: [segId],
419	      category,
420	      attributedSource,
421	      sourceRefs: seg.sourceRefs,
422	      mechanism,
423	      confidence,
424	      charCount: chars,
425	      tokenEstimate: seg.tokenEstimate ?? Math.round(chars / 4),
426	      ...(notes ? { notes } : {}),
427	      ...(ruleId ? { ruleId } : {}),
428	      ...(lifecycle || flags.length > 0
429	        ? { metadata: { ...(lifecycle ? { lifecycle } : {}), ...(flags.length > 0 ? { flags } : {}) } }
430	        : {}),
431	    });
432	  }
433	
434	  return results;
435	}
436	
437	// ── 分析工具 ──────────────────────────────────────────────────────────────────
438	
439	export interface AttributionBreakdown {
440	  fixture: string;
441	  totalSegments: number;
442	  byCategory: Array<{
443	    category: SegmentCategory;
444	    count: number;
445	    totalChars: number;
446	    mechanisms: string[];
447	    confidences: string[];
448	  }>;
449	  topBloatSources: Array<{
450	    proxySegmentId: string;
451	    category: SegmentCategory;
452	    charCount: number;
453	    jsonPath: string;
454	  }>;
455	  unknownSegments: Array<{
456	    proxySegmentId: string;
457	    jsonPath: string;
458	    charCount: number;
459	    note: string;
460	    nextStepEvidence: string;
461	  }>;
462	}
463	
464	export function buildAttributionBreakdown(
465	  fixtureName: string,
466	  attributions: ProxySegmentAttribution[],
467	): AttributionBreakdown {
468	  const catMap = new Map<
469	    SegmentCategory,
470	    { count: number; totalChars: number; mechanisms: Set<string>; confidences: Set<string> }
471	  >();
472	
473	  for (const attr of attributions) {
474	    const existing = catMap.get(attr.category) ?? {
475	      count: 0,
476	      totalChars: 0,
477	      mechanisms: new Set<string>(),
478	      confidences: new Set<string>(),
479	    };
480	    existing.count += 1;
481	    existing.totalChars += attr.charCount ?? 0;
482	    existing.mechanisms.add(attr.mechanism);
483	    existing.confidences.add(attr.confidence);
484	    catMap.set(attr.category, existing);
485	  }
486	
487	  const byCategory = Array.from(catMap.entries())
488	    .sort((a, b) => b[1].totalChars - a[1].totalChars)
489	    .map(([category, v]) => ({
490	      category,
491	      count: v.count,
492	      totalChars: v.totalChars,
493	      mechanisms: Array.from(v.mechanisms),
494	      confidences: Array.from(v.confidences),
495	    }));
496	
497	  const topBloatSources = [...attributions]
498	    .sort((a, b) => (b.charCount ?? 0) - (a.charCount ?? 0))
499	    .slice(0, 5)
500	    .map((attr) => ({
501	      proxySegmentId: attr.proxySegmentIds[0] ?? "?",
502	      category: attr.category,
503	      charCount: attr.charCount ?? 0,
504	      jsonPath:
505	        (attr.sourceRefs[0] as Extract<typeof attr.sourceRefs[0], { kind: "proxy" }>)?.proxy
506	          ?.jsonPath ?? "?",
507	    }));
508	
509	  const unknownSegments = attributions
510	    .filter((attr) => attr.category === "unknown")
511	    .map((attr) => {
512	      const jsonPath =
513	        (attr.sourceRefs[0] as Extract<typeof attr.sourceRefs[0], { kind: "proxy" }>)?.proxy
514	          ?.jsonPath ?? "?";
515	      return {
516	        proxySegmentId: attr.proxySegmentIds[0] ?? "?",
517	        jsonPath,
518	        charCount: attr.charCount ?? 0,
519	        note: attr.notes?.join("; ") ?? "no note",
520	        nextStepEvidence:
521	          "需要 JSONL reconciliation 或人工标注来确认来源；可能是 compaction summary、memory injection、或未知 harness rule。",
522	      };
523	    });
524	
525	  return {
526	    fixture: fixtureName,
527	    totalSegments: attributions.length,
528	    byCategory,
529	    topBloatSources,
530	    unknownSegments,
531	  };
532	}
