1	// Proxy Attribution View
2	// 四列 HTML，专注于 proxy → parser → attribution 的完整链路。
3	// 不展示 expected / mutation / reconciliation。
4	//
5	// 列定义：
6	//   col-1 Raw Original  — reqBody 原始明文，直接从 JSON 取，不经过 parser
7	//   col-2 Parser        — parseClaudeProxyRequest 产出的 segment（id/category/metadata）
8	//   col-3 Attribution   — inferClaudeProxyAttributions 产出（category/mechanism/ruleId/notes）
9	//
10	// 三列通过 segment id 对齐，点击行互相高亮。
11	
12	import { CONTEXT_LEDGER_RULE_BY_ID } from "../rule-registry";
13	import type { ContextLedgerRule } from "../rule-registry";
14	import type { ContextSegment, ProxySegmentAttribution } from "../types";
15	
16	// ── 颜色 / badge 映射 ─────────────────────────────────────────────────────────
17	
18	const CATEGORY_COLOR: Record<string, string> = {
19	  billing_noise:        "#6b7280",
20	  system_prompt:        "#3b82f6",
21	  harness_injection:    "#8b5cf6",
22	  tools_schema:         "#f59e0b",
23	  tool_use:             "#10b981",
24	  tool_result:          "#059669",
25	  user_message:         "#0ea5e9",
26	  assistant_text:       "#64748b",
27	  local_command_history:"#d97706",
28	  prior_session_history:"#a78bfa",
29	  unknown:              "#ef4444",
30	};
31	
32	function categoryColor(cat: string): string {
33	  return CATEGORY_COLOR[cat] ?? "#94a3b8";
34	}
35	
36	function badge(text: string, color: string, title?: string): string {
37	  const t = title ? ` title="${esc(title)}"` : "";
38	  return `<span class="badge"${t} style="background:${color}20;color:${color};border:1px solid ${color}40">${esc(text)}</span>`;
39	}
40	
41	function confidenceBadge(conf: string): string {
42	  const colors: Record<string, string> = { exact: "#10b981", estimated: "#f59e0b", inferred: "#94a3b8", unknown: "#ef4444" };
43	  return badge(conf, colors[conf] ?? "#94a3b8");
44	}
45	
46	function esc(s: string): string {
47	  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
48	}
49	
50	function truncate(s: string, n: number): string {
51	  if (s.length <= n) return s;
52	  return s.slice(0, n) + "…";
53	}
54	
55	// ── reqBody 原文提取 ──────────────────────────────────────────────────────────
56	
57	function walkPath(path: string, root: unknown): unknown {
58	  const tokens = path.split(/\.|\[(\d+)\]/).filter((t) => t !== undefined && t !== "");
59	  let cur: unknown = root;
60	  for (const tok of tokens) {
61	    if (cur === null || cur === undefined) return undefined;
62	    const idx = parseInt(tok, 10);
63	    if (!isNaN(idx)) cur = (cur as unknown[])[idx];
64	    else cur = (cur as Record<string, unknown>)[tok];
65	  }
66	  return cur;
67	}
68	
69	// 从 reqBody 取 segment 对应的原始文本。
70	// 对 system/messages text block → 取 .text 字段，再用 charRange 切片（sub-section 时）
71	// 对 tools → JSON.stringify
72	// 对 tool_use / tool_result → 取相关字段文本
73	function extractRawOriginal(
74	  seg: ContextSegment,
75	  reqBody: Record<string, unknown>,
76	): string | null {
77	  const ref = seg.sourceRefs[0];
78	  if (!ref || ref.kind !== "proxy" || !ref.proxy.jsonPath) return null;
79	
80	  const path = ref.proxy.jsonPath.startsWith("reqBody.")
81	    ? ref.proxy.jsonPath.slice("reqBody.".length)
82	    : ref.proxy.jsonPath;
83	
84	  const value = walkPath(path, reqBody);
85	  if (value === undefined || value === null) return null;
86	
87	  // object with .text field（system block / message content block）
88	  if (typeof value === "object" && !Array.isArray(value)) {
89	    const obj = value as Record<string, unknown>;
90	    if (typeof obj["text"] === "string") {
91	      const text = obj["text"] as string;
92	      const range = ref.proxy.charRange;
93	      // sub-section: 用 charRange 切片还原该 section 的原始文本
94	      if (range) return text.slice(range.start, range.end);
95	      return text;
96	    }
97	    return JSON.stringify(obj, null, 2);
98	  }
99	
100	  if (typeof value === "string") return value;
101	
102	  // tools[i]：JSON
103	  return JSON.stringify(value, null, 2);
104	}
105	
106	// ── 数据准备 ─────────────────────────────────────────────────────────────────
107	
108	interface SegmentRow {
109	  seg: ContextSegment;
110	  attr: ProxySegmentAttribution | undefined;
111	}
112	
113	function buildRows(
114	  segments: ContextSegment[],
115	  attributions: ProxySegmentAttribution[],
116	): SegmentRow[] {
117	  const attrById = new Map<string, ProxySegmentAttribution>();
118	  for (const a of attributions) {
119	    for (const id of a.proxySegmentIds) attrById.set(id, a);
120	  }
121	  return segments.map((seg) => ({ seg, attr: attrById.get(seg.id) }));
122	}
123	
124	// ── 第一列：Raw Original（reqBody 原始明文）───────────────────────────────────
125	
126	function renderRawOriginalCell(row: SegmentRow, reqBody: Record<string, unknown>): string {
127	  const rawText = extractRawOriginal(row.seg, reqBody) ?? "";
128	  const ref = row.seg.sourceRefs[0];
129	  const jsonPath = ref?.kind === "proxy" ? (ref.proxy.jsonPath ?? "?") : "?";
130	  const charRange = ref?.kind === "proxy" ? ref.proxy.charRange : undefined;
131	  const rangeStr = charRange ? `[${charRange.start}…${charRange.end})` : "";
132	
133	  if (!rawText) {
134	    return `<div class="raw-orig-cell"><div class="path-line"><code class="path">${esc(jsonPath)}</code></div><span class="no-text">—</span></div>`;
135	  }
136	
137	  const chars = rawText.length;
138	  // 直接展示，不折叠——这是"原文列"的核心诉求
139	  return `
140	    <div class="raw-orig-cell">
141	      <div class="path-line">
142	        <code class="path">${esc(jsonPath)}</code>
143	        ${rangeStr ? `<span class="range">${esc(rangeStr)}</span>` : ""}
144	        <span class="chars">${chars.toLocaleString()}c</span>
145	      </div>
146	      <pre class="raw-orig-text">${esc(rawText.slice(0, 3000))}${rawText.length > 3000 ? "\n…(truncated)" : ""}</pre>
147	    </div>`;
148	}
149	
150	// ── 第二列：Parser Segments ───────────────────────────────────────────────────
151	
152	function renderParserCell(row: SegmentRow): string {
153	  const { seg } = row;
154	  const color = categoryColor(seg.category);
155	  const meta = seg.metadata as Record<string, unknown> | undefined;
156	  const sectionHeader = typeof meta?.["sectionHeader"] === "string" ? meta["sectionHeader"] : null;
157	  const ref = seg.sourceRefs[0];
158	  const charRange = ref?.kind === "proxy" ? ref.proxy.charRange : undefined;
159	  const rangeStr = charRange ? `[${charRange.start}…${charRange.end})` : "";
160	
161	  return `
162	    <div class="parser-cell">
163	      <div class="seg-id"><code>${esc(seg.id)}</code></div>
164	      <div class="seg-meta">
165	        ${badge(seg.section, "#6b7280")}
166	        ${badge(seg.category, color)}
167	        ${seg.lifecycle ? badge(seg.lifecycle, "#94a3b8") : ""}
168	        ${seg.flags?.includes("large_segment") ? badge("large", "#ef4444") : ""}
169	        ${seg.flags?.includes("known_noise") ? badge("noise", "#6b7280") : ""}
170	      </div>
171	      ${sectionHeader ? `<div class="section-header">§ ${esc(sectionHeader)}</div>` : ""}
172	      ${rangeStr ? `<div class="range-hint">${esc(rangeStr)} · ${(seg.charCount ?? 0).toLocaleString()}c</div>` : ""}
173	      ${seg.toolUseId ? `<div class="tool-id"><code>${esc(seg.toolUseId)}</code></div>` : ""}
174	      ${seg.cacheHint && seg.cacheHint !== "none" ? badge(seg.cacheHint, "#f59e0b") : ""}
175	    </div>`;
176	}
177	
178	// ── 第三列：Attribution ───────────────────────────────────────────────────────
179	
180	// stability → badge 颜色
181	const STABILITY_COLOR: Record<string, string> = {
182	  static:      "#10b981",  // green
183	  "semi-static": "#f59e0b",
184	  dynamic:     "#8b5cf6",  // purple
185	};
186	
187	function renderAttrCell(row: SegmentRow): string {
188	  const { attr, seg } = row;
189	  if (!attr) {
190	    return `<div class="attr-cell attr-missing"><span class="no-attr">— no attribution —</span></div>`;
191	  }
192	
193	  const color = categoryColor(attr.category);
194	  const PARSER_AUTHORITATIVE = new Set(["tool_use", "tool_result", "tools_schema"]);
195	  const categoryMismatch = attr.category !== seg.category && PARSER_AUTHORITATIVE.has(seg.category);
196	
197	  // 从 rule-registry 取 rule 详情
198	  const rule: ContextLedgerRule | undefined = attr.ruleId
199	    ? CONTEXT_LEDGER_RULE_BY_ID.get(attr.ruleId)
200	    : undefined;
201	
202	  const ruleDetail = rule
203	    ? `
204	      <details class="rule-detail">
205	        <summary class="rule-summary">
206	          <code class="rule-id-text">${esc(rule.ruleId)}</code>
207	        </summary>
208	        <div class="rule-body">
209	          <div class="rule-desc">${esc(rule.description)}</div>
210	          <div class="rule-props">
211	            ${badge(rule.stability, STABILITY_COLOR[rule.stability] ?? "#94a3b8", "stability")}
212	            ${rule.attribution?.matchMode ? badge(rule.attribution.matchMode, "#475569", "matchMode") : ""}
213	            ${rule.reconciliation?.comparePolicy ? badge(rule.reconciliation.comparePolicy, "#334155", "comparePolicy") : ""}
214	            ${rule.reconstruction?.materialization ? badge(rule.reconstruction.materialization, "#1e3a5f", "materialization") : ""}
215	          </div>
216	          ${rule.sourcemapRef ? `<div class="rule-src">src: <code>${esc(rule.sourcemapRef.slice(0, 60))}${rule.sourcemapRef.length > 60 ? "…" : ""}</code></div>` : ""}
217	          ${rule.reconstruction?.preCondition
218	            ? `<div class="rule-precond">if: <code>${esc(rule.reconstruction.preCondition)}</code></div>`
219	            : ""}
220	        </div>
221	      </details>`
222	    : attr.ruleId
223	      ? `<div class="rule-id"><code>${esc(attr.ruleId)}</code> <span style="color:#ef4444;font-size:9px">not in registry</span></div>`
224	      : "";
225	
226	  return `
227	    <div class="attr-cell ${categoryMismatch ? "category-override" : ""}">
228	      <div class="attr-category">
229	        ${badge(attr.category, color)}
230	        ${categoryMismatch ? `<span class="override-hint" title="parser: ${esc(seg.category)}">← override</span>` : ""}
231	      </div>
232	      <div class="attr-meta">
233	        <code class="mechanism">${esc(attr.mechanism)}</code>
234	        ${confidenceBadge(attr.confidence)}
235	      </div>
236	      ${ruleDetail}
237	      ${attr.notes?.length ? `
238	        <details class="attr-notes">
239	          <summary>${attr.notes.length} note${attr.notes.length > 1 ? "s" : ""}</summary>
240	          <ul>${attr.notes.map((n) => `<li>${esc(n)}</li>`).join("")}</ul>
241	        </details>` : ""}
242	    </div>`;
243	}
244	
245	// ── メイン HTML レンダー ───────────────────────────────────────────────────────
246	
247	export interface ProxyAttributionViewInput {
248	  snapshotId: string;
249	  queryId: string;
250	  sessionId: string;
251	  timestamp: string;
252	  segments: ContextSegment[];
253	  attributions: ProxySegmentAttribution[];
254	  reqBody: Record<string, unknown>;
255	  proxySourceRef?: string;
256	}
257	
258	export function renderProxyAttributionView(input: ProxyAttributionViewInput): string {
259	  const { queryId, sessionId, timestamp, segments, attributions, reqBody, proxySourceRef } = input;
260	  const rows = buildRows(segments, attributions);
261	
262	  const sectionOrder: ContextSegment["section"][] = ["system", "tools", "messages", "metadata", "unknown"];
263	  const grouped = new Map<string, SegmentRow[]>();
264	  for (const s of sectionOrder) grouped.set(s, []);
265	  for (const row of rows) {
266	    const key = row.seg.section;
267	    if (!grouped.has(key)) grouped.set(key, []);
268	    grouped.get(key)!.push(row);
269	  }
270	
271	  const sectionBlocks = [...grouped.entries()]
272	    .filter(([, r]) => r.length > 0)
273	    .map(([section, sectionRows]) => {
274	      const totalChars = sectionRows.reduce((s, r) => s + (r.seg.charCount ?? 0), 0);
275	      const rowHtml = sectionRows.map((row) => {
276	        const segId = row.seg.id.replace(/[^a-zA-Z0-9-_]/g, "_");
277	        return `
278	          <tr class="seg-row" id="row-${segId}" data-segid="${esc(row.seg.id)}"
279	              onclick="highlightRow('${esc(row.seg.id)}')">
280	            <td class="col-raw-orig">${renderRawOriginalCell(row, reqBody)}</td>
281	            <td class="col-parser">${renderParserCell(row)}</td>
282	            <td class="col-attr">${renderAttrCell(row)}</td>
283	          </tr>`;
284	      }).join("");
285	
286	      return `
287	        <tr class="section-header-row">
288	          <td colspan="3">
289	            <div class="section-banner">
290	              <span class="section-name">${esc(section)}</span>
291	              <span class="section-stats">${sectionRows.length} segments · ${totalChars.toLocaleString()} chars</span>
292	            </div>
293	          </td>
294	        </tr>
295	        ${rowHtml}`;
296	    }).join("");
297	
298	  // summary stats
299	  const attrMap = new Map<string, ProxySegmentAttribution>();
300	  for (const a of attributions) for (const id of a.proxySegmentIds) attrMap.set(id, a);
301	  const categoryCounts = new Map<string, number>();
302	  for (const a of attributions) {
303	    categoryCounts.set(a.category, (categoryCounts.get(a.category) ?? 0) + 1);
304	  }
305	  const ruledCount = attributions.filter((a) => a.ruleId).length;
306	
307	  const summaryBadges = [...categoryCounts.entries()]
308	    .sort((a, b) => b[1] - a[1])
309	    .map(([cat, cnt]) => badge(`${cat} ×${cnt}`, categoryColor(cat)))
310	    .join(" ");
311	
312	  return `<!DOCTYPE html>
313	<html lang="zh">
314	<head>
315	<meta charset="utf-8">
316	<title>Proxy Attribution View · ${esc(queryId.slice(-12))}</title>
317	<style>
318	* { box-sizing: border-box; margin: 0; padding: 0; }
319	body { font-family: ui-monospace, 'Cascadia Code', monospace; font-size: 12px;
320	       background: #0f172a; color: #e2e8f0; }
321	
322	/* ── header ── */
323	.view-header { padding: 16px 20px; border-bottom: 1px solid #1e293b; background: #1e293b; }
324	.view-title { font-size: 14px; font-weight: 600; color: #f1f5f9; }
325	.view-meta { margin-top: 6px; color: #94a3b8; font-size: 11px; }
326	.view-meta span { margin-right: 16px; }
327	.summary-row { margin-top: 10px; display: flex; gap: 16px; flex-wrap: wrap; align-items: center; }
328	.stat { color: #94a3b8; }
329	.stat b { color: #e2e8f0; }
330	
331	/* ── table layout：3列 ── */
332	table { width: 100%; border-collapse: collapse; table-layout: fixed; }
333	col.col-raw-orig { width: 38%; }
334	col.col-parser   { width: 22%; }
335	col.col-attr     { width: 40%; }
336	
337	/* ── section banner ── */
338	.section-header-row td { padding: 0; }
339	.section-banner { padding: 6px 12px; background: #1e293b;
340	                  border-top: 2px solid #334155; display: flex; gap: 12px; align-items: center; }
341	.section-name { font-weight: 700; color: #7dd3fc; font-size: 11px; text-transform: uppercase;
342	                letter-spacing: 0.08em; }
343	.section-stats { color: #64748b; font-size: 11px; }
344	
345	/* ── segment rows ── */
346	.seg-row td { padding: 8px 12px; vertical-align: top; border-bottom: 1px solid #1e293b; }
347	.seg-row:hover td { background: #1e293b80; }
348	.seg-row.highlighted td { background: #1e3a5f; outline: 1px solid #3b82f6; }
349	
350	/* ── col-1: raw original ── */
351	.raw-orig-cell { }
352	.path-line { display: flex; align-items: center; gap: 6px; flex-wrap: wrap; margin-bottom: 4px; }
353	.path { color: #7dd3fc; font-size: 10px; }
354	.range { color: #475569; font-size: 10px; }
355	.chars { color: #475569; font-size: 10px; }
356	.raw-orig-text {
357	  font-size: 10px; white-space: pre-wrap; word-break: break-all;
358	  color: #cbd5e1; max-height: 240px; overflow-y: auto;
359	  border: 1px solid #1e293b; border-radius: 3px; padding: 6px;
360	  background: #080f1a;
361	  line-height: 1.5;
362	}
363	.no-text { color: #475569; }
364	
365	/* ── col-2: parser ── */
366	.seg-id code { color: #a78bfa; font-size: 10px; display: block; margin-bottom: 4px; }
367	.seg-meta { display: flex; gap: 4px; flex-wrap: wrap; margin-bottom: 4px; }
368	.section-header { color: #fbbf24; font-size: 11px; margin-top: 2px; }
369	.range-hint { color: #475569; font-size: 10px; margin-top: 2px; }
370	.tool-id code { color: #34d399; font-size: 10px; }
371	
372	/* ── col-3: attribution ── */
373	.attr-category { display: flex; align-items: center; gap: 6px; margin-bottom: 4px; }
374	.override-hint { color: #f59e0b; font-size: 10px; font-style: italic; }
375	.category-override { border-left: 3px solid #f59e0b; padding-left: 6px !important; }
376	.attr-meta { display: flex; gap: 6px; align-items: center; flex-wrap: wrap; margin-bottom: 4px; }
377	.mechanism { color: #94a3b8; font-size: 10px; }
378	.rule-id code { color: #34d399; font-size: 10px; display: block; margin-top: 2px; }
379	.attr-notes summary { cursor: pointer; color: #94a3b8; font-size: 10px; margin-top: 4px; }
380	.attr-notes ul { margin-top: 4px; padding-left: 12px; }
381	.attr-notes li { color: #94a3b8; font-size: 10px; margin-bottom: 2px; }
382	.attr-missing { color: #475569; }
383	.no-attr { font-size: 11px; }
384	
385	/* ── rule detail（折叠展开） ── */
386	.rule-detail { margin-top: 4px; }
387	.rule-summary { cursor: pointer; list-style: none; display: flex; align-items: center; gap: 4px; }
388	.rule-summary::-webkit-details-marker { display: none; }
389	.rule-id-text { color: #34d399; font-size: 10px; }
390	details.rule-detail[open] .rule-id-text::before { content: "▾ "; }
391	details.rule-detail:not([open]) .rule-id-text::before { content: "▸ "; }
392	.rule-body { margin-top: 4px; padding: 6px 8px; background: #0a1628;
393	             border-radius: 4px; border: 1px solid #1e3a5f; }
394	.rule-desc { color: #cbd5e1; font-size: 10px; margin-bottom: 4px; line-height: 1.4; }
395	.rule-props { display: flex; gap: 4px; flex-wrap: wrap; margin-bottom: 4px; }
396	.rule-src { color: #475569; font-size: 9px; margin-top: 2px; }
397	.rule-src code { color: #64748b; }
398	.rule-precond { color: #94a3b8; font-size: 9px; margin-top: 2px; }
399	.rule-precond code { color: #7dd3fc; }
400	
401	/* ── badge ── */
402	.badge { display: inline-block; padding: 1px 6px; border-radius: 3px;
403	         font-size: 10px; font-weight: 500; white-space: nowrap; }
404	
405	/* ── column headers ── */
406	.col-headers th { padding: 8px 12px; background: #0f172a; color: #64748b;
407	                  font-size: 11px; text-align: left; font-weight: 600;
408	                  border-bottom: 2px solid #1e293b; position: sticky; top: 0; z-index: 10; }
409	</style>
410	</head>
411	<body>
412	
413	<div class="view-header">
414	  <div class="view-title">Proxy Attribution View</div>
415	  <div class="view-meta">
416	    <span>queryId: <b>${esc(queryId)}</b></span>
417	    <span>session: <b>${esc(sessionId.slice(0, 8))}…</b></span>
418	    <span>${esc(timestamp)}</span>
419	    ${proxySourceRef ? `<span>${esc(proxySourceRef)}</span>` : ""}
420	  </div>
421	  <div class="summary-row">
422	    <span class="stat"><b>${segments.length}</b> segments</span>
423	    <span class="stat"><b>${ruledCount}</b> with ruleId</span>
424	    <span style="flex:1">${summaryBadges}</span>
425	  </div>
426	</div>
427	
428	<table>
429	  <colgroup>
430	    <col class="col-raw-orig">
431	    <col class="col-parser">
432	    <col class="col-attr">
433	  </colgroup>
434	  <thead>
435	    <tr class="col-headers">
436	      <th>Raw（reqBody 原文）</th>
437	      <th>Parser Segments</th>
438	      <th>Attribution</th>
439	    </tr>
440	  </thead>
441	  <tbody>
442	    ${sectionBlocks}
443	  </tbody>
444	</table>
445	
446	<script>
447	function highlightRow(segId) {
448	  document.querySelectorAll('.seg-row.highlighted').forEach(el => el.classList.remove('highlighted'));
449	  const row = document.getElementById('row-' + segId.replace(/[^a-zA-Z0-9-_]/g, '_'));
450	  if (row) {
451	    row.classList.add('highlighted');
452	    row.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
453	  }
454	}
