1	// char-diff.ts — Gate 3.5 Alignment Precision Audit
2	//
3	// Bypass / debug-only tool. NOT imported by any production path.
4	// Computes char-level diff between ExpectedQueryContext segments and
5	// ProxyQuerySnapshot segments as aligned by a ReconciliationReport.
6	//
7	// Design goals:
8	//   - Surface alignment gaps and char-count mismatches in human-readable form.
9	//   - Work directly from ReconciliationReport (no additional parsing needed).
10	//   - Performance-insensitive: correctness over speed.
11	
12	import type {
13	  AlignmentRef,
14	  ContextSegment,
15	  ExpectedQueryContext,
16	  ProxyQuerySnapshot,
17	  ReconciliationFinding,
18	  ReconciliationReport,
19	  SegmentCategory,
20	} from "../types";
21	
22	// ─────────────────────────────────────────────────────────────────────────────
23	// Public output types
24	// ─────────────────────────────────────────────────────────────────────────────
25	
26	export type DiffKind =
27	  | "matched_exact"        // rawHash / tool_use_id 精确匹配，chars 完全相同
28	  | "matched_char_diff"    // 有内容锚点匹配，但 char count 有差异（evidence-backed）
29	  | "suspect_match"        // 仅 category+role heuristic，无内容锚点，不计入 evidence-backed
30	  | "expected_only"        // expected segment 无对应 proxy
31	  | "proxy_only"           // proxy segment 未被任何 alignment 覆盖（unattributed）
32	  | "attribution_only"     // proxy segment 有 server-side attribution，无对应 expected（非 user-semantic）
33	  | "known_noise";         // 已知非用户语义的 server-side attribution（billing_noise 等）
34	
35	export interface CharRange {
36	  start: number;  // inclusive char offset in the concatenated flat text
37	  end: number;    // exclusive
38	  chars: number;
39	}
40	
41	export interface SegmentText {
42	  /** segment label for display */
43	  label: string;
44	  /** full text if available (contentRef.kind=inline) */
45	  text?: string;
46	  /** char count */
47	  chars: number;
48	  /** segment id */
49	  segmentId: string;
50	}
51	
52	export interface SegmentDiffEntry {
53	  kind: DiffKind;
54	  category: SegmentCategory;
55	  label: string;
56	  /** char range in the "expected flat text" (undefined for proxy_only / attribution_only / known_noise) */
57	  expectedRange?: CharRange;
58	  /** char range in the "proxy flat text" (undefined for expected_only) */
59	  proxyRange?: CharRange;
60	  /** char count delta: expectedChars - proxyChars (0 for non-matched, undefined if not applicable) */
61	  charDelta?: number;
62	  /** absolute char delta as percentage of proxy chars (0..1) */
63	  charDeltaPct?: number;
64	  alignmentId?: string;
65	  expectedSegmentIds: string[];
66	  proxySegmentIds: string[];
67	  findingIds: string[];
68	  notes: string[];
69	  /** expandable text content, one entry per segment on each side */
70	  expectedTexts?: SegmentText[];
71	  proxyTexts?: SegmentText[];
72	}
73	
74	export interface CharDiffReport {
75	  queryId: string;
76	  sessionId: string;
77	  generatedAt: string;
78	  entries: SegmentDiffEntry[];
79	  summary: CharDiffSummary;
80	  /** flat concatenation of all expected segment texts (by charCount) for range display */
81	  expectedFlatChars: number;
82	  /** flat concatenation of all proxy segment texts (by charCount) for range display */
83	  proxyFlatChars: number;
84	}
85	
86	export interface CharDiffSummary {
87	  totalEntries: number;
88	  matchedExact: number;
89	  matchedWithCharDiff: number;
90	  // suspect_match：category+role heuristic，无内容锚点，不计入 evidence-backed
91	  suspectMatch: number;
92	  expectedOnly: number;
93	  // proxy_only：unattributed proxy segment，既无 alignment 也无 attribution
94	  proxyOnly: number;
95	  // attribution_only：server-side attribution 已识别（非 user-semantic），但无对应 expected
96	  attributionOnly: number;
97	  // known_noise：已知非用户语义的 server-side overhead（billing_noise 等），不宣称 token 节约
98	  knownNoise: number;
99	  totalExpectedChars: number;
100	  totalProxyChars: number;
101	  // unexplainedProxyChars：仅表示 unattributed proxy（proxy_only + suspect_match），
102	  // attribution_only 和 known_noise 不在此列
103	  unexplainedProxyChars: number;
104	  /** sum of |charDelta| across matched_char_diff entries */
105	  totalCharDriftAbsolute: number;
106	  /** totalCharDriftAbsolute / totalProxyChars (0..1)；仅表示 aligned 部分的 drift，=0 不代表 proxy==expected */
107	  charDriftPct: number;
108	
109	  // ── 细化覆盖率拆分 ──────────────────────────────────────────────────────────
110	  /** proxy chars 中有 server-side attribution（含 evidence-backed），占 totalProxyChars 的比例 (0..1) */
111	  attributionCoverage: number;
112	  /** proxy chars 中有内容锚点证明（matched_exact + matched_char_diff），占 totalProxyChars 的比例 (0..1) */
113	  evidenceBackedCoverage: number;
114	  /** attributionCoverage - evidenceBackedCoverage：归因知晓但无 JSONL/ruleId 锚点的 gap (0..1) */
115	  attributionOnlyGap: number;
116	  /** suspect_match proxy chars（有 alignment 但无内容锚点），绝对值 */
117	  suspectMatchChars: number;
118	  /** evidence-backed matched 中 |expectedChars - proxyChars| 之和 / totalProxyChars；=0 仅代表 aligned 段无漂移 */
119	  alignedTextDrift: number;
120	}
121	
122	// ─────────────────────────────────────────────────────────────────────────────
123	// Main entry point
124	// ─────────────────────────────────────────────────────────────────────────────
125	
126	export function computeCharDiff(report: ReconciliationReport): CharDiffReport {
127	  const { snapshot, expected, alignments, findings } = report;
128	
129	  const expectedSegs = expected?.segments ?? [];
130	  const proxySegs = snapshot.segments;
131	
132	  // Build lookup indices
133	  const expectedById = new Map<string, ContextSegment>(expectedSegs.map((s) => [s.id, s]));
134	  const proxyById = new Map<string, ContextSegment>(proxySegs.map((s) => [s.id, s]));
135	  const findingsByAlignId = buildFindingsByAlignId(findings);
136	  const findingsByExpectedId = buildFindingsBySegId(findings, "expected");
137	  const findingsByProxyId = buildFindingsBySegId(findings, "proxy");
138	
139	  // Assign flat char offsets (ordered by segment.order, then insertion order)
140	  const expectedOffsets = buildFlatOffsets(expectedSegs);
141	  const proxyOffsets = buildFlatOffsets(proxySegs);
142	
143	  const entries: SegmentDiffEntry[] = [];
144	  const coveredExpectedIds = new Set<string>();
145	  const coveredProxyIds = new Set<string>();
146	
147	  // ── Process each alignment ─────────────────────────────────────────────────
148	  for (const align of alignments) {
149	    const relatedFindings = findingsByAlignId.get(align.id) ?? [];
150	    const findingIds = relatedFindings.map((f) => f.id);
151	
152	    const eSegs = align.expectedSegmentIds.map((id) => expectedById.get(id)).filter(Boolean) as ContextSegment[];
153	    const pSegs = align.proxySegmentIds.map((id) => proxyById.get(id)).filter(Boolean) as ContextSegment[];
154	
155	    for (const id of align.expectedSegmentIds) coveredExpectedIds.add(id);
156	    for (const id of align.proxySegmentIds) coveredProxyIds.add(id);
157	
158	    const kind = classifyAlignmentKind(align, eSegs, pSegs, findings);
159	    const category = (eSegs[0] ?? pSegs[0])?.category ?? "unknown";
160	    const label = buildLabel(eSegs, pSegs, align);
161	
162	    const expectedRange = eSegs.length > 0 ? mergeRanges(eSegs.map((s) => expectedOffsets.get(s.id)!)) : undefined;
163	    const proxyRange = pSegs.length > 0 ? mergeRanges(pSegs.map((s) => proxyOffsets.get(s.id)!)) : undefined;
164	
165	    const expectedChars = eSegs.reduce((s, seg) => s + (seg.charCount ?? 0), 0);
166	    const proxyChars = pSegs.reduce((s, seg) => s + (seg.charCount ?? 0), 0);
167	    const charDelta = eSegs.length > 0 && pSegs.length > 0 ? expectedChars - proxyChars : undefined;
168	    const charDeltaPct =
169	      charDelta !== undefined && proxyChars > 0 ? Math.abs(charDelta) / proxyChars : undefined;
170	
171	    const notes = buildNotes(align, relatedFindings);
172	
173	    entries.push({
174	      kind,
175	      category,
176	      label,
177	      expectedRange,
178	      proxyRange,
179	      charDelta,
180	      charDeltaPct,
181	      alignmentId: align.id,
182	      expectedSegmentIds: align.expectedSegmentIds,
183	      proxySegmentIds: align.proxySegmentIds,
184	      findingIds,
185	      notes,
186	      expectedTexts: eSegs.length > 0 ? eSegs.map(segmentText) : undefined,
187	      proxyTexts: pSegs.length > 0 ? pSegs.map(segmentText) : undefined,
188	    });
189	  }
190	
191	  // ── Unmatched expected segments ────────────────────────────────────────────
192	  for (const eseg of expectedSegs) {
193	    if (coveredExpectedIds.has(eseg.id)) continue;
194	    const relatedFindings = findingsByExpectedId.get(eseg.id) ?? [];
195	    entries.push({
196	      kind: "expected_only",
197	      category: eseg.category,
198	      label: eseg.label,
199	      expectedRange: expectedOffsets.get(eseg.id),
200	      charDelta: -(eseg.charCount ?? 0),
201	      expectedSegmentIds: [eseg.id],
202	      proxySegmentIds: [],
203	      findingIds: relatedFindings.map((f) => f.id),
204	      notes: [`expected segment not matched in proxy (${eseg.charCount ?? 0} chars)`],
205	      expectedTexts: [segmentText(eseg)],
206	    });
207	  }
208	
209	  // ── Unmatched proxy segments (not covered by any alignment) ───────────────
210	  for (const pseg of proxySegs) {
211	    if (coveredProxyIds.has(pseg.id)) continue;
212	    const relatedFindings = findingsByProxyId.get(pseg.id) ?? [];
213	    entries.push({
214	      kind: "proxy_only",
215	      category: pseg.category,
216	      label: pseg.label,
217	      proxyRange: proxyOffsets.get(pseg.id),
218	      charDelta: pseg.charCount ?? 0,
219	      proxySegmentIds: [pseg.id],
220	      expectedSegmentIds: [],
221	      findingIds: relatedFindings.map((f) => f.id),
222	      notes: [`proxy segment not covered by any alignment (${pseg.charCount ?? 0} chars)`],
223	      proxyTexts: [segmentText(pseg)],
224	    });
225	  }
226	
227	  // Sort entries by proxy range start, then expected range start
228	  entries.sort((a, b) => {
229	    const ap = a.proxyRange?.start ?? a.expectedRange?.start ?? Infinity;
230	    const bp = b.proxyRange?.start ?? b.expectedRange?.start ?? Infinity;
231	    return ap - bp;
232	  });
233	
234	  const summary = computeSummary(entries, snapshot, expected);
235	  const expectedFlatChars = expectedSegs.reduce((s, seg) => s + (seg.charCount ?? 0), 0);
236	  const proxyFlatChars = proxySegs.reduce((s, seg) => s + (seg.charCount ?? 0), 0);
237	
238	  return {
239	    queryId: report.queryId,
240	    sessionId: report.sessionId,
241	    generatedAt: new Date().toISOString(),
242	    entries,
243	    summary,
244	    expectedFlatChars,
245	    proxyFlatChars,
246	  };
247	}
248	
249	// ─────────────────────────────────────────────────────────────────────────────
250	// Internal helpers
251	// ─────────────────────────────────────────────────────────────────────────────
252	
253	function segmentText(seg: ContextSegment): SegmentText {
254	  return {
255	    label: seg.label,
256	    text: seg.contentRef?.kind === "inline" ? seg.contentRef.text : undefined,
257	    chars: seg.charCount ?? 0,
258	    segmentId: seg.id,
259	  };
260	}
261	
262	function buildFlatOffsets(segs: ContextSegment[]): Map<string, CharRange> {
263	  const sorted = [...segs].sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
264	  const m = new Map<string, CharRange>();
265	  let cursor = 0;
266	  for (const seg of sorted) {
267	    const chars = seg.charCount ?? 0;
268	    m.set(seg.id, { start: cursor, end: cursor + chars, chars });
269	    cursor += chars;
270	  }
271	  return m;
272	}
273	
274	function mergeRanges(ranges: (CharRange | undefined)[]): CharRange | undefined {
275	  const valid = ranges.filter(Boolean) as CharRange[];
276	  if (valid.length === 0) return undefined;
277	  const start = Math.min(...valid.map((r) => r.start));
278	  const end = Math.max(...valid.map((r) => r.end));
279	  return { start, end, chars: end - start };
280	}
281	
282	function classifyAlignmentKind(
283	  align: AlignmentRef,
284	  eSegs: ContextSegment[],
285	  pSegs: ContextSegment[],
286	  findings: ReconciliationFinding[],
287	): DiffKind {
288	  // known_noise: billing_noise proxy segments
289	  if (pSegs.length > 0 && pSegs.every((s) => s.category === "billing_noise")) {
290	    return "known_noise";
291	  }
292	  const alignFindings = findings.filter((f) => f.alignmentIds?.includes(align.id));
293	  if (alignFindings.some((f) => f.type === "known_noise")) {
294	    return "known_noise";
295	  }
296	
297	  // attribution_only: proxy segment has attribution but no expected counterpart
298	  if (eSegs.length === 0 && pSegs.length > 0) {
299	    return "attribution_only";
300	  }
301	
302	  // expected_only: no proxy segment
303	  if (pSegs.length === 0 && eSegs.length > 0) {
304	    return "expected_only";
305	  }
306	
307	  // suspect_match：category+role heuristic（basis=category），无内容锚点，不算 evidence-backed
308	  if (align.basis === "category" || alignFindings.some((f) => f.type === "suspect_match")) {
309	    return "suspect_match";
310	  }
311	
312	  // Both sides present with content anchor — check char diff
313	  const expectedChars = eSegs.reduce((s, seg) => s + (seg.charCount ?? 0), 0);
314	  const proxyChars = pSegs.reduce((s, seg) => s + (seg.charCount ?? 0), 0);
315	  const delta = Math.abs(expectedChars - proxyChars);
316	  const pct = proxyChars > 0 ? delta / proxyChars : 0;
317	
318	  if (pct > 0.01 || delta > 10) {
319	    return "matched_char_diff";
320	  }
321	  return "matched_exact";
322	}
323	
324	function buildLabel(
325	  eSegs: ContextSegment[],
326	  pSegs: ContextSegment[],
327	  align: AlignmentRef,
328	): string {
329	  const primary = eSegs[0] ?? pSegs[0];
330	  if (!primary) return `align:${align.id}`;
331	  const suffix = eSegs.length > 1 || pSegs.length > 1
332	    ? ` [${eSegs.length}E:${pSegs.length}P]`
333	    : "";
334	  return `${primary.label}${suffix}`;
335	}
336	
337	function buildNotes(align: AlignmentRef, relatedFindings: ReconciliationFinding[]): string[] {
338	  const notes: string[] = [];
339	  if (align.note) notes.push(align.note);
340	  notes.push(`basis:${align.basis} confidence:${align.confidence} matchKind:${align.matchKind}`);
341	  for (const f of relatedFindings) {
342	    if (f.type !== "matched" && f.type !== "known_noise") {
343	      notes.push(`[${f.type}] ${f.message}`);
344	    }
345	  }
346	  return notes;
347	}
348	
349	function buildFindingsByAlignId(
350	  findings: ReconciliationFinding[],
351	): Map<string, ReconciliationFinding[]> {
352	  const m = new Map<string, ReconciliationFinding[]>();
353	  for (const f of findings) {
354	    for (const id of f.alignmentIds ?? []) {
355	      const arr = m.get(id) ?? [];
356	      arr.push(f);
357	      m.set(id, arr);
358	    }
359	  }
360	  return m;
361	}
362	
363	function buildFindingsBySegId(
364	  findings: ReconciliationFinding[],
365	  side: "expected" | "proxy",
366	): Map<string, ReconciliationFinding[]> {
367	  const m = new Map<string, ReconciliationFinding[]>();
368	  const key = side === "expected" ? "expectedSegmentIds" : "proxySegmentIds";
369	  for (const f of findings) {
370	    for (const id of f[key] ?? []) {
371	      const arr = m.get(id) ?? [];
372	      arr.push(f);
373	      m.set(id, arr);
374	    }
375	  }
376	  return m;
377	}
378	
379	function computeSummary(
380	  entries: SegmentDiffEntry[],
381	  snapshot: ProxyQuerySnapshot,
382	  expected: ExpectedQueryContext | undefined,
383	): CharDiffSummary {
384	  let matchedExact = 0;
385	  let matchedWithCharDiff = 0;
386	  let suspectMatch = 0;
387	  let expectedOnly = 0;
388	  let proxyOnly = 0;
389	  let attributionOnly = 0;
390	  let knownNoise = 0;
391	  let totalCharDriftAbsolute = 0;
392	
393	  // 用于细化覆盖率的字符累计
394	  let evidenceBackedChars = 0;   // matched_exact + matched_char_diff 的 proxy chars
395	  let attributionChars = 0;      // attribution_only + known_noise + evidence-backed 的 proxy chars
396	  let suspectMatchChars = 0;     // suspect_match 的 proxy chars
397	
398	  for (const e of entries) {
399	    // proxyRange 是 bounding box（mergeRanges），多 segment 不连续时会包含中间无关字符；
400	    // 用 proxyTexts 逐段求和才是真实的 proxy chars
401	    const pChars = (e.proxyTexts ?? []).reduce((s, t) => s + t.chars, 0);
402	    switch (e.kind) {
403	      case "matched_exact":
404	        matchedExact++;
405	        evidenceBackedChars += pChars;
406	        attributionChars += pChars;
407	        break;
408	      case "matched_char_diff":
409	        matchedWithCharDiff++;
410	        totalCharDriftAbsolute += Math.abs(e.charDelta ?? 0);
411	        evidenceBackedChars += pChars;
412	        attributionChars += pChars;
413	        break;
414	      case "suspect_match":
415	        suspectMatch++;
416	        suspectMatchChars += pChars;
417	        // suspect 不计入 evidenceBackedChars，也不计入 attributionChars
418	        break;
419	      case "expected_only": expectedOnly++; break;
420	      case "proxy_only": proxyOnly++; break;
421	      case "attribution_only":
422	        // server-side attribution（非 user-semantic）：归因知晓但无 expected 对应
423	        attributionOnly++;
424	        attributionChars += pChars;
425	        break;
426	      case "known_noise":
427	        // 已知非用户语义的 server-side overhead，不宣称 token 节约
428	        knownNoise++;
429	        attributionChars += pChars;
430	        break;
431	    }
432	  }
433	
434	  const totalExpectedChars = (expected?.segments ?? []).reduce((s, seg) => s + (seg.charCount ?? 0), 0);
435	  const totalProxyChars = snapshot.segments.reduce((s, seg) => s + (seg.charCount ?? 0), 0);
436	
437	  // unexplainedProxyChars：仅 unattributed proxy（proxy_only + suspect_match）
438	  // attribution_only / known_noise 已有 server-side attribution，不算 unexplained
439	  const unexplainedProxyChars = entries
440	    .filter((e) => e.kind === "proxy_only" || e.kind === "suspect_match")
441	    .reduce((s, e) => s + (e.proxyTexts ?? []).reduce((t, seg) => t + seg.chars, 0), 0);
442	
443	  const charDriftPct = totalProxyChars > 0 ? totalCharDriftAbsolute / totalProxyChars : 0;
444	
445	  // 细化覆盖率（0..1）
446	  const evidenceBackedCoverage = totalProxyChars > 0 ? evidenceBackedChars / totalProxyChars : 0;
447	  const attributionCoverage = totalProxyChars > 0 ? attributionChars / totalProxyChars : 0;
448	  const attributionOnlyGap = Math.max(0, attributionCoverage - evidenceBackedCoverage);
449	  // alignedTextDrift：evidence-backed matched 中的文本漂移 / totalProxyChars
450	  // =0 仅表示已匹配段无漂移，不意味着 proxy == expected
451	  const alignedTextDrift = totalProxyChars > 0 ? totalCharDriftAbsolute / totalProxyChars : 0;
452	
453	  return {
454	    totalEntries: entries.length,
455	    matchedExact,
456	    matchedWithCharDiff,
457	    suspectMatch,
458	    expectedOnly,
459	    proxyOnly,
460	    attributionOnly,
461	    knownNoise,
462	    totalExpectedChars,
463	    totalProxyChars,
464	    unexplainedProxyChars,
465	    totalCharDriftAbsolute,
466	    charDriftPct: Math.round(charDriftPct * 10000) / 10000,
467	    attributionCoverage: Math.round(attributionCoverage * 10000) / 10000,
468	    evidenceBackedCoverage: Math.round(evidenceBackedCoverage * 10000) / 10000,
469	    attributionOnlyGap: Math.round(attributionOnlyGap * 10000) / 10000,
470	    suspectMatchChars,
471	    alignedTextDrift: Math.round(alignedTextDrift * 10000) / 10000,
472	  };
473	}
