42	// AuditVerdict → ChangeClass 映射（两者字面量不同，as 强转会产生错误值）
43	function verdictToChangeClass(v: AuditVerdict): ChangeClass {
44	  if (v === "improvement") return "improved";
45	  if (v === "regression")  return "regressed";
46	  if (v === "needs_review") return "needs_review";
47	  if (v === "unchanged")   return "unchanged";
48	  if (v === "skipped")     return "skipped";
49	  if (v === "failed")      return "failed";
50	  return "unchanged";  // "ok" fallback
51	}
