56	
57	export function ensureAuditDirs(runId: string): string {
58	  const dir = runDir(runId);
59	  for (const sub of ["reports", "scorecards", "diffs", "logs"]) {
60	    mkdirSync(join(dir, sub), { recursive: true });
61	  }
62	  return dir;
63	}
