65	// ─────────────────────────────────────────────────────────────────────────────
66	// 读取 baseline run 的 index.json（用于 delta 计算）
67	// ─────────────────────────────────────────────────────────────────────────────
68	
69	export interface BaselineIndex {
70	  entries: AuditIndexEntry[];
71	  scorecardByHash: Map<string, QueryScorecard>;
72	}
73	
74	export function loadBaselineIndex(baselineRunId: string | undefined): BaselineIndex | null {
75	  if (!baselineRunId) return null;
76	  const indexFile = join(runDir(baselineRunId), "index.json");
77	  if (!existsSync(indexFile)) return null;
78	
79	  try {
80	    const entries = JSON.parse(readFileSync(indexFile, "utf-8")) as AuditIndexEntry[];
81	    const scorecardByHash = new Map<string, QueryScorecard>();
82	
83	    for (const entry of entries) {
84	      if (!entry.scorecardPath) continue;
85	      const scFile = join(runDir(baselineRunId), entry.scorecardPath);
86	      if (!existsSync(scFile)) continue;
87	      try {
88	        const sc = JSON.parse(readFileSync(scFile, "utf-8")) as QueryScorecard;
89	        scorecardByHash.set(entry.queryKeyHash, sc);
90	      } catch { /* skip */ }
91	    }
92	
93	    return { entries, scorecardByHash };
94	  } catch {
95	    return null;
96	  }
97	}
