99	// ─────────────────────────────────────────────────────────────────────────────
100	// 写 per-query artifacts
101	// ─────────────────────────────────────────────────────────────────────────────
102	
103	export function writeQueryArtifacts(
104	  runId: string,
105	  result: PipelineResult,
106	  data?: {
107	    report: ReconciliationReport;
108	    diff: CharDiffReport;
109	    diffHtml: string;
110	    attributions?: ProxySegmentAttribution[];
111	    reqBody?: Record<string, unknown>;
112	  },
113	): PipelineResult {
114	  const dir = runDir(runId);
115	  const hash = result.queryKeyHash;
