bun --eval "
import { readFileSync } from 'fs';
import { parseClaudeProxyRequest } from './server/src/context-ledger/proxy-snapshot-parser';
import { inferClaudeProxyAttributions } from './server/src/context-ledger/proxy-attribution';
import { parseClaudeJsonlMutations } from './server/src/context-ledger/jsonl-mutation-parser';
import { reconstructExpectedClaudeContext } from './server/src/context-ledger/expected-context-reconstructor';
import { reconcileClaudeContext } from './server/src/context-ledger/reconciliation-engine';
import { computeCharDiff } from './server/src/context-ledger/debug/char-diff';

const proxyRaw = JSON.parse(readFileSync('server/test/fixtures/context-reconstruction/multi-turn-human/proxy-request.json', 'utf-8'));
const jsonlRaw = readFileSync('server/test/fixtures/context-reconstruction/multi-turn-human/session.jsonl', 'utf-8');

const snapshot = parseClaudeProxyRequest({ reqBody: proxyRaw.reqBody, ts: proxyRaw.ts, startedAt: proxyRaw.startedAt, reqHeaders: proxyRaw.reqHeaders, _sse_events: proxyRaw._sse_events });
const attrs = inferClaudeProxyAttributions({ ...snapshot, metadata: { ...snapshot.metadata, rawBody: proxyRaw.reqBody } });
const parsed = parseClaudeJsonlMutations(jsonlRaw, {});
const expected = reconstructExpectedClaudeContext({ mutations: parsed.mutations, boundary: { queryId: snapshot.queryId, proxyTimestamp: snapshot.timestamp, sessionId: parsed.sessionId }, hasPreSessionActivity: parsed.hasPreSessionActivity });
const report = reconcileClaudeContext({ snapshot, attributions: attrs, expected });
const diff = computeCharDiff(report);

console.log('entries:', diff.entries.length);
console.log('matched exact:', diff.summary.matchedExact);
console.log('expected only:', diff.summary.expectedOnly);
console.log('proxy only:', diff.summary.proxyOnly);
console.log('attribution only:', diff.summary.attributionOnly);
" 2>&1

