        const segId = row.seg.id.replace(/[^a-zA-Z0-9-_]/g, "_");
        return `
          <tr class="seg-row" id="row-${segId}" data-segid="${esc(row.seg.id)}"
              onclick="highlightRow('${esc(row.seg.id)}')">
