    <tr class="section-header-row">
      <td colspan="${colCount}">
        <div class="section-banner">
          <span class="section-name" style="color:#3b82f6">expected only</span>
          <span class="section-stats">${expectedOnlySegs.length} segments · no proxy counterpart</span>
